static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // 192KB
static constexpr uint32_t ALIGN_ELEMS = 32;              // Align to 32 elements

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    ConvStandard3dAsymmetricInputAsymmetricKernelCustomTilingData tiling;

    // Input shapes: x shape [N, C, D, H, W], weight shape [outC, inC/groups, kD, kH, kW]
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    const uint32_t N   = x_shape->GetDim(0);
    const uint32_t inC = x_shape->GetDim(1);
    const uint32_t D   = x_shape->GetDim(2);
    const uint32_t H   = x_shape->GetDim(3);
    const uint32_t W   = x_shape->GetDim(4);

    const uint32_t outC = w_shape->GetDim(0);
    const uint32_t kD   = w_shape->GetDim(2);
    const uint32_t kH   = w_shape->GetDim(3);
    const uint32_t kW   = w_shape->GetDim(4);

    // Attributes
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *stride   = attrs->GetAttrPointer<int32_t>(0);
    const int32_t *padding  = attrs->GetAttrPointer<int32_t>(1);
    const int32_t *dilation = attrs->GetAttrPointer<int32_t>(2);
    const int32_t groups    = *attrs->GetAttrPointer<int32_t>(3);

    uint32_t strideD = static_cast<uint32_t>(stride[0]);
    uint32_t strideH = static_cast<uint32_t>(stride[1]);
    uint32_t strideW = static_cast<uint32_t>(stride[2]);
    uint32_t padD    = static_cast<uint32_t>(padding[0]);
    uint32_t padH    = static_cast<uint32_t>(padding[1]);
    uint32_t padW    = static_cast<uint32_t>(padding[2]);
    uint32_t dilationD = static_cast<uint32_t>(dilation[0]);
    uint32_t dilationH = static_cast<uint32_t>(dilation[1]);
    uint32_t dilationW = static_cast<uint32_t>(dilation[2]);

    // Compute output dimensions
    uint32_t D_out = (D + 2 * padD - dilationD * (kD - 1) - 1) / strideD + 1;
    uint32_t H_out = (H + 2 * padH - dilationH * (kH - 1) - 1) / strideH + 1;
    uint32_t W_out = (W + 2 * padW - dilationW * (kW - 1) - 1) / strideW + 1;

    uint32_t totalLength = N * outC * D_out * H_out * W_out;

    // Estimate tile size
    // For each output element, we need to load:
    //   - input patch: (inC/groups) * kD * kH * kW floats
    //   - weight slice: same size
    // So 2 * (inC/groups) * kD * kH * kW floats per element.
    uint32_t elemMem = 2 * (inC / groups) * kD * kH * kW; // floats
    uint32_t maxTile = UB_BUDGET_BYTES / (elemMem * sizeof(float));
    if (maxTile < 1) maxTile = 1;
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;

    uint32_t tileLength = maxTile;
    if (totalLength < tileLength) {
        uint32_t aligned = AlignDown(totalLength, ALIGN_ELEMS);
        tileLength = (aligned > 0) ? aligned : totalLength;
    }

    // Determine blockDim
    uint32_t numTiles = (tileLength == 0) ? 1 : CeilDiv(totalLength, tileLength);
    uint32_t blockDim = numTiles;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLength);
    tiling.set_blockDim(blockDim);
    tiling.set_N(N);
